    if (self.buffer_effective[word.start].equals_base('G') and self.buffer_effective[word.start + 1].equals_base('I')) {
        consonant_special_start_exists = true;
    } else if (self.buffer_effective[word.start].equals_base('Q') and self.buffer_effective[word.start + 1].equals_ignore_case_and_tone('U', .empty)) {
        consonant_special_start_exists = true;
    }

    var index: u8 = vowels_end + 1;

