905:     // Append literal character when possible. Then inclease the buffer_length.
906:     fn append_literal(self: *State, c: u8) void {
907:         // Only allow a-zA-Z.
908:         assert(std.ascii.isAlphabetic(c));
909:         // Could not append if the buffer_length is full.
910:         assert(self.buffer_length < std.math.maxInt(@TypeOf(self.buffer_length)));
911: 
912:         // Check if we can add new span for input character.
913:         if (self.buffer_length < self.buffer_effective.len) {
914:             // Add character to span.
915:             self.buffer_effective[self.buffer_length] = Span.init(c);
916:         }
917:         // Increase the buffer length for tracking, we will need it went handling backspace.
918:         self.buffer_length += 1;
919: 
920:         // After increase, the new buffer_length may exceed the buffer_effective, set literal_index if needed.
921:         if (self.mode == .telex and self.literal_index == null and self.buffer_length == self.buffer_effective.len + 1) {
922:             self.literal_index = self.buffer_length - 1;
923:         }
924:     }
