926:     // Return the last item in buffer_effective, not valid if the buffer_length is out of range.
927:     fn buffer_effective_last(self: *State) Span {
928:         // 1. Should not work if buffer_length exceed buffer_effective.
929:         // 2. Bufeer must have al least 1 character.
930:         assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
931: 
932:         return self.buffer_effective[self.buffer_length - 1];
933:     }
