935:     // Return the pseudoword when scan backward the buffer_effective.
936:     fn pseudoword(self: *State) Pseudoword {
937:         // Only scan when buffer has characters and doesn't exceed buffer_effective length.
938:         assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
939: 
940:         // Scan the buffer_effective backward.
941:         var word_start: ?u8 = null;
942:         var vowels_start: ?u8 = null;
