945:         while (index > 0) {
946:             index -= 1;
947:             const sp = self.buffer_effective[index];
948:             const is_vowel = switch (std.ascii.toUpper(sp.base)) {
949:                 'A', 'E', 'I', 'O', 'U', 'Y' => true,
950:                 else => false,
951:             };
952:             const is_consonant = !is_vowel;
953: 
