1148:     fn backspace(self: *State) void {
1149:         // buffer_length must be positive for backspace.
1150:         assert(self.buffer_length > 0);
1151: 
1152:         // Input mode must be either .literal or .telex.
1153:         assert(self.mode == .literal or self.mode == .telex);
1154: 
1155:         if (self.literal_index) |literal_index| {
1156:             // Input mode must be .telex when literal_index is set.
1157:             assert(self.mode == .telex);
1158:             // literal_index must be within buffer range when set.
1159:             assert(literal_index < self.buffer_length);
1160:         }
1161: 
1162:         // decrease the buffer_length to match the backspace.
1163:         self.buffer_length -= 1;
1164:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
1165:         self.buffer_modification_index = null;
1166:         // if the literal_index is out of buffer range, unset it.
1167:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
1168:             self.literal_index = null;
1169:         }
